import json

review_counts = locals()['var_function-call-13353977543139218697']
if isinstance(review_counts, str) and review_counts.endswith('.json'):
    with open(review_counts, 'r') as f:
        review_counts = json.load(f)

ids = []
for rc in review_counts:
    bref = rc['business_ref']
    # convert businessref_X to businessid_X
    bid = bref.replace('businessref_', 'businessid_')
    ids.append(bid)

# Create Mongo query
query = {
    "collection": "business",
    "filter": {
        "business_id": {"$in": ids}
    },
    "projection": {
        "business_id": 1,
        "description": 1
    }
}
print("__RESULT__:")
print(json.dumps(query))

